import React, {
  useEffect,
  useState
} from "react";

import { getUsers } from "../api/admin";

import "../styles/Layouts.css";
import "../styles/Cards.css";
import "../styles/Tables.css";

function Admin() {

  const [users, setUsers] = useState([]);

  const loadUsers = async () => {
    try {

      const res = await getUsers();

      setUsers(
        res.data.data
      );

    } catch (err) {

      alert(
        err?.response?.data?.message ||
        "Không tải được danh sách người dùng"
      );

    }
  };

  useEffect(() => {
    loadUsers();
  }, []);

  const totalAdmins =
    users.filter(
      u => u.role === "ADMIN"
    ).length;

  const totalUsers =
    users.filter(
      u => u.role === "USER"
    ).length;

  return (

    <div className="page">

      <h2>
        👑 Admin Dashboard
      </h2>

      <div className="grid-3">

        <div className="stat-card">
          <h3>
            Tổng tài khoản
          </h3>

          <p>
            {users.length}
          </p>
        </div>

        <div className="stat-card">
          <h3>
            Admin
          </h3>

          <p>
            {totalAdmins}
          </p>
        </div>

        <div className="stat-card">
          <h3>
            User
          </h3>

          <p>
            {totalUsers}
          </p>
        </div>

      </div>

      <div className="card">

        <h3>
          Danh sách người dùng
        </h3>

        <table className="data-table">

          <thead>

            <tr>
              <th>ID</th>
              <th>Họ tên</th>
              <th>Email</th>
              <th>Role</th>
              <th>Ngày tạo</th>
            </tr>

          </thead>

          <tbody>

            {users.map((u) => (

              <tr
                key={u.user_id}
              >

                <td>
                  {u.user_id}
                </td>

                <td>
                  {u.full_name}
                </td>

                <td>
                  {u.email}
                </td>

                <td>
                  {u.role === "ADMIN"
                    ? "👑 ADMIN"
                    : "👤 USER"}
                </td>

                <td>
                  {new Date(
                    u.created_at
                  ).toLocaleDateString()}
                </td>

              </tr>

            ))}

          </tbody>

        </table>

      </div>

    </div>

  );

}

export default Admin;
